import React from 'react'


export default function StatsPanel({ analysis }){
if(!analysis) return (
<div className="p-2 text-center text-gray-500">Waiting for data...</div>
)
const label = analysis.label || 'Unknown'
const probs = Array.isArray(analysis.probs) ? analysis.probs : []
const confidence = probs.length ? (Math.max(...probs) * 100).toFixed(1) : '--'
const hrv = analysis.hrv && analysis.hrv.heart_rate ? analysis.hrv.heart_rate : (analysis.hrv ? JSON.stringify(analysis.hrv) : '--')
const risk = typeof analysis.risk === 'number' ? analysis.risk : '--'


const getRiskColor = (r) => {
if (r === '--') return 'bg-gray-200 text-gray-700'
if (r < 30) return 'bg-green-100 text-green-800'
if (r < 70) return 'bg-yellow-100 text-yellow-800'
return 'bg-red-100 text-red-800'
}


return (
<div>
<div className={`p-3 rounded ${getRiskColor(risk)}`}>
<div className="text-sm">Detection</div>
<div className="text-2xl font-bold">{label}</div>
<div className="text-sm mt-1">Confidence: <strong>{confidence}%</strong></div>
</div>


<div className="mt-4">
<h4 className="text-sm font-medium">HRV / Heart Rate</h4>
<div className="text-lg">{hrv}</div>
</div>


<div className="mt-4">
<h4 className="text-sm font-medium">Risk</h4>
<div className="text-lg">{risk}%</div>
</div>


{analysis.probs && (
<div className="mt-4">
<h4 className="text-sm font-medium">Probabilities</h4>
<ul className="text-sm list-disc list-inside">
{analysis.probs.map((p,i)=> (
<li key={i}>{p.toFixed(3)}</li>
))}
</ul>
</div>
)}
</div>
)
}