import React from 'react'
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip } from 'recharts'


export default function ECGChart({ data }){
// data: [{index, time, value}, ...]
// downsample for chart performance
const maxPoints = 1200
const step = Math.max(1, Math.floor(Math.max(1, data.length / maxPoints)))
const sampled = data.filter((_,i) => i % step === 0).map((d,i)=>({ x:i, value:d.value }))


return (
<div style={{ width: '100%', height: 320 }}>
<LineChart width={900} height={320} data={sampled}>
<CartesianGrid strokeDasharray="3 3" />
<XAxis dataKey="x" hide />
<YAxis domain={['auto','auto']} width={60} />
<Tooltip />
<Line type="monotone" dataKey="value" stroke="#1f2937" dot={false} isAnimationActive={false} strokeWidth={1} />
</LineChart>
</div>
)
}