import React, { useEffect, useRef, useState } from 'react'
import ECGChart from './components/ECGChart'
import RiskHistory from './components/RiskHistory'
import StatsPanel from './components/StatsPanel'
import axios from 'axios'


// CONFIG
const BACKEND_PREDICT_URL = 'http://localhost:5000/infer' // change if needed
const WS_URL = 'ws://192.168.4.1:81' // ESP32 websocket streaming raw samples (replace with your address)
const WINDOW_LEN = 1000
const SEND_INTERVAL_MS = 1500 // attempt inference every 1.5s


export default function App() {
const [raw, setRaw] = useState([]) // raw numeric values
const [analysis, setAnalysis] = useState(null)
const [history, setHistory] = useState([]) // risk history
const wsRef = useRef(null)
const sendingRef = useRef(false)


// setup websocket to receive raw samples from ESP32 (it broadcasts numeric strings)
useEffect(() => {
try {
    wsRef.current = new WebSocket(WS_URL)
    wsRef.current.onopen = () => console.log('ws open')
    wsRef.current.onmessage = (ev) => {
    const val = Number(ev.data)
    if (!Number.isFinite(val)) return
    setRaw(prev => {
    const next = prev.concat({ time: Date.now(), value: val })
    if (next.length > 4000) next.splice(0, next.length - 4000)
    return next
    })
    }
    wsRef.current.onclose = () => console.log('ws closed')
    } catch (e) {
    console.warn('WS failed', e)
    }
    return () => { if (wsRef.current) wsRef.current.close() }
    }, [])


// periodic inference sender
useEffect(() => {
const id = setInterval(async () => {
if (sendingRef.current) return
if (raw.length < 200) return
const latest = raw.slice(-WINDOW_LEN).map(d => d.value)
if (latest.length < 100) return
// only send if we have at least 1000 or pad/crop on server
sendingRef.current = true
try {
const resp = await axios.post(BACKEND_PREDICT_URL, { ecg: latest, fs: 200 }, { timeout: 5000 })
if (resp && resp.data) {
setAnalysis(resp.data)
const r = resp.data.risk || (resp.data.risk === 0 ? 0 : null)
if (r !== null) {
setHistory(h => [...h.slice(-59), { time: new Date().toLocaleTimeString(), risk: r }])
}
}
} catch (e) {
// console.error('infer err', e)
} finally {
sendingRef.current = false
}
}, SEND_INTERVAL_MS)
return () => clearInterval(id)
}, [raw])


return (
<div className="min-h-screen bg-gray-50 p-6 font-sans">
<div className="max-w-6xl mx-auto">
<header className="flex items-center justify-between mb-6">
<h1 className="text-3xl font-bold">ECG AI — Live Monitoring</h1>
<div className="text-sm text-gray-600">Status: {wsRef.current && wsRef.current.readyState === 1 ? <span className="text-green-600">Connected</span> : <span className="text-red-600">Disconnected</span>}</div>
</header>


<div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
<div className="lg:col-span-2 bg-white p-4 rounded shadow">
<h2 className="text-xl font-semibold mb-2">Live ECG</h2>
<ECGChart data={raw.map((d,i) => ({ index: i, time: d.time, value: d.value }))} />
</div>


<div className="bg-white p-4 rounded shadow">
<StatsPanel analysis={analysis} />
</div>
</div>


<div className="mt-6 bg-white p-4 rounded shadow">
<h3 className="text-lg font-semibold mb-2">Risk History</h3>
<RiskHistory history={history} />
</div>


</div>
</div>
)
}
